import React, { useEffect, useState } from "react";

import SplashScreen from "./screens/SplashScreen";
import SignInScreen from "./screens/SignInScreen";
import SignUpScreen from "./screens/SignUpScreen";
import HomeScreen from "./screens/HomeScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawScreen";
import SavingsDepositScreen from "./screens/SavingsDepositScreen";
import SavingsWithdrawScreen from "./screens/SavingsWithdrawScreen";
import TransactionsHistoryScreen from "./screens/TransactionHistoryScreen";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen";
import AddMoneyOptionsScreen from "./screens/AddMoneyOptionsScreen";
import PaymentProcessingScreen from "./screens/PaymentProcessingScreen";
import PaymentSuccessScreen from "./screens/PaymentSuccessScreen";
import GoalsScreen from "./screens/GoalsScreen";
import LoansScreen from "./screens/LoansScreen";
import ProfileScreen from "./screens/ProfileScreen";
import BottomNav from "./components/BottomNav";
import TransactionResultScreen from "./screens/TransactionResultScreen";


import CreateGoalScreen from "./screens/CreateGoalScreen";
import GoalDetailsScreen from "./screens/GoalDetailsScreen";
import AddGoalFundScreen from "./screens/AddGoalFundScreen";
import WithdrawGoalScreen from "./screens/WithdrawGoalScreen";

import CreditScoreDetailScreen from "./screens/CreditScoreDetailScreen";
import LoanApplicationScreen from "./screens/LoanApplicationScreen";
import LoanTermsScreen from "./screens/LoanTermsScreen";
import PinScreen from "./screens/PinScreen";

/* 🔹 ADDED */
import ConfirmPaymentScreen from "./screens/ConfirmPaymentScreen";
import AddPaymentSourceScreen from "./screens/AddPaymentSourceScreen";

import { generateReference } from "./helpers/reference";
import { CurrencyProvider } from "./context/CurrencyContext";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Splash");
  const [prevScreen, setPrevScreen] = useState(null); // 🔹 Track previous screen
  const [activeTab, setActiveTab] = useState("home");
  const [darkMode, setDarkMode] = useState(false);

  const [user, setUser] = useState(null);
  const [balance, setBalance] = useState(0);
  const [savingsBalance, setSavingsBalance] = useState(0);
  const [transactions, setTransactions] = useState([]);
  const [goals, setGoals] = useState([]);

  const [selectedTransaction, setSelectedTransaction] = useState(null);
  const [selectedGoal, setSelectedGoal] = useState(null);

  /* 🔹 pending transaction & action */
  const [pendingPayment, setPendingPayment] = useState(null);
  const [pendingAction, setPendingAction] = useState(null);
  const [requirePin, setRequirePin] = useState(false);
  const [transactionResult, setTransactionResult] = useState(null);
  const [lastTransaction, setLastTransaction] = useState(null);


  /* ---------- LOAD STORAGE ---------- */
  useEffect(() => {
    const u = localStorage.getItem("user");
    const b = localStorage.getItem("balance");
    const s = localStorage.getItem("savingsBalance");
    const t = localStorage.getItem("transactions");
    const g = localStorage.getItem("goals");

    if (u) setUser(JSON.parse(u));
    if (b) setBalance(Number(b));
    if (s) setSavingsBalance(Number(s));
    if (t) setTransactions(JSON.parse(t));
    if (g) setGoals(JSON.parse(g));
  }, []);

  /* ---------- SAVE STORAGE ---------- */
  useEffect(() => {
    if (user) localStorage.setItem("user", JSON.stringify(user));
    localStorage.setItem("balance", balance);
    localStorage.setItem("savingsBalance", savingsBalance);
    localStorage.setItem("transactions", JSON.stringify(transactions));
    localStorage.setItem("goals", JSON.stringify(goals));
  }, [user, balance, savingsBalance, transactions, goals]);

  /* ---------- GLOBAL TAB HANDLER ---------- */
  const handleTabChange = (tab) => {
    setActiveTab(tab);
    setCurrentScreen("Main");
  };

  /* ---------- NAVIGATION ---------- */
  const openScreen = (screen, data = null) => {
    if (screen === "TransactionReceipt") setSelectedTransaction(data);
    if (screen === "GoalDetailsScreen") setSelectedGoal(data);
    if (screen === "AddGoalFundScreen" || screen === "WithdrawGoalScreen") {
      setSelectedGoal(data);
    }
    setCurrentScreen(screen);
  };

  const goHome = () => {
    setCurrentScreen("Main");
    setActiveTab("home");
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.clear();
    setCurrentScreen("SignIn");
  };

  /* ---------- TRANSACTIONS ---------- */
  const addTransaction = (tx) => {
    setTransactions((prev) => [tx, ...prev]);
  };

  const handleDeposit = (amount) => {
    if (amount <= 0) return;
    setBalance((b) => b + amount);
    addTransaction({
      id: Date.now(),
      reference: generateReference(),
      title: "Deposit",
      amount,
      type: "deposit",
      date: new Date().toDateString(),
    });
  };

  const handleWithdraw = (amount) => {
    if (amount <= 0 || amount > balance) return;
    setBalance((b) => b - amount);
    addTransaction({
      id: Date.now(),
      reference: generateReference(),
      title: "Withdrawal",
      amount,
      type: "withdraw",
      date: new Date().toDateString(),
    });
  };

  const handleSavingsDeposit = (amount) => {
    if (amount <= 0) return;
    setSavingsBalance((s) => s + amount);
    addTransaction({
      id: Date.now(),
      reference: generateReference(),
      title: "Savings Deposit",
      amount,
      type: "savings-deposit",
      date: new Date().toDateString(),
    });
  };

  const handleSavingsWithdraw = (amount) => {
    if (amount <= 0 || amount > savingsBalance) return;
    setSavingsBalance((s) => s - amount);
    addTransaction({
      id: Date.now(),
      reference: generateReference(),
      title: "Savings Withdraw",
      amount,
      type: "savings-withdraw",
      date: new Date().toDateString(),
    });
  };

  const commonScreenProps = {
    darkMode,
    toggleDarkMode: () => setDarkMode((d) => !d),
  };

  /* ---------- PIN FLOW ---------- */
    const handlePinSuccess = () => {
      setRequirePin(false);

      if (typeof pendingAction === "function") {
        pendingAction(); // → PaymentProcessing
      }

      setPendingAction(null);
      setPrevScreen(null);
      // ❗ DO NOT clear pendingPayment here
    };

  /* ---------- SAFE BACK HANDLER ---------- */
  const handleBack = () => {
    if (currentScreen === "ConfirmPayment" || currentScreen === "Pin") {
      setRequirePin(false);
      setPendingAction(null);
      setPendingPayment(null);
      setCurrentScreen(prevScreen || "Main");
    } else if (currentScreen === "PaymentProcessing") {
      // optionally alert user that transaction is in progress
      return;
    } else if (currentScreen === "PaymentSuccess") {
      goHome();
    } else {
      goHome();
    }
  };

  return (
    <CurrencyProvider>
      <div className={`min-h-screen flex flex-col ${darkMode ? "bg-gray-900 text-white" : "bg-gray-50 text-gray-900"}`}>

        {/* ---------- SPLASH ---------- */}
        {currentScreen === "Splash" && (
          <SplashScreen onFinish={() => setCurrentScreen(user ? "Main" : "SignIn")} />
        )}

        {/* ---------- AUTH ---------- */}
        {currentScreen === "SignIn" && (
          <SignInScreen
            onSignIn={(u) => {
              setUser(u);
              goHome();
            }}
            onNavigateToSignUp={() => setCurrentScreen("SignUp")}
          />
        )}

        {currentScreen === "SignUp" && (
          <SignUpScreen
            onSignUp={(u) => {
              setUser(u);
              goHome();
            }}
            onNavigateToSignIn={() => setCurrentScreen("SignIn")}
          />
        )}

        {/* ---------- MAIN ---------- */}
        {currentScreen === "Main" && (
          <>
            {activeTab === "home" && (
              <HomeScreen
                {...commonScreenProps}
                balance={balance}
                savingsBalance={savingsBalance}
                transactions={transactions}
                userName={user?.name || "Pips"}
                openScreen={openScreen}
              />
            )}

            {activeTab === "goals" && <GoalsScreen openScreen={openScreen} goals={goals} />}
            {activeTab === "loans" && <LoansScreen openScreen={openScreen} />}
            {activeTab === "profile" && <ProfileScreen user={user} onLogout={handleLogout} />}

            <BottomNav active={activeTab} setActive={handleTabChange} darkMode={darkMode} />
          </>
        )}

        {/* ---------- PIN SCREEN ---------- */}
              {requirePin && currentScreen === "Pin" && (
          <PinScreen
            darkMode={darkMode}
            onBack={handleBack}
            onSuccess={handlePinSuccess}
          />
        )}

        {/* ---------- DEPOSIT ---------- */}
        {currentScreen === "Deposit" && (
          <DepositScreen
            onBack={goHome}
            onConfirm={(data) => {
              setPrevScreen("Deposit");
              setPendingPayment(data);
              setPendingAction(() => () => setCurrentScreen("PaymentProcessing"));
              setCurrentScreen("ConfirmPayment");
            }}
          />
        )}

        {currentScreen === "ConfirmPayment" && pendingPayment && (
          <ConfirmPaymentScreen
            {...pendingPayment}
            onBack={handleBack}
            onConfirm={() => {
              setPrevScreen("ConfirmPayment");
              setRequirePin(true);
              setCurrentScreen("Pin");
            }}
          />
        )}

        {currentScreen === "PaymentProcessing" && pendingPayment && (
          <PaymentProcessingScreen
            message="Processing your transaction securely..."
            onComplete={() => {
              const { type, amount } = pendingPayment;

              const isFailed = pendingPayment.shouldFail === true;

          if (!isFailed) {
            switch (type) {
              case "deposit":
                handleDeposit(amount);
                break;
              case "withdraw":
                handleWithdraw(amount);
                break;
              case "savings-deposit":
                handleSavingsDeposit(amount);
                break;
              case "savings-withdraw":
                handleSavingsWithdraw(amount);
                break;
              case "goal-fund":
                setBalance((b) => b - amount);
                addTransaction({
                  id: Date.now(),
                  reference: generateReference(),
                  title: `Added to Goal: ${pendingPayment.goalName}`,
                  amount,
                  type: "goal-fund",
                  date: new Date().toDateString(),
                });
                break;
              case "goal-withdraw":
                setBalance((b) => b + amount);
                addTransaction({
                  id: Date.now(),
                  reference: generateReference(),
                  title: `Withdraw from Goal: ${pendingPayment.goalName}`,
                  amount,
                  type: "goal-withdraw",
                  date: new Date().toDateString(),
                });
                break;
              default:
                break;
            }
          }

                            setTransactionResult({
            status: isFailed ? "failed" : "success",
            amount: pendingPayment.amount,
            type: pendingPayment.type,
          });


            setPendingPayment(null);
            setCurrentScreen("TransactionResult");

            }}
          />
        )}

              {currentScreen === "TransactionResult" && transactionResult && (
          <TransactionResultScreen
            status={transactionResult.status}
            amount={transactionResult.amount}
            type={transactionResult.type}
            onDone={() => {
              setTransactionResult(null);
              goHome();
            }}
          />
        )}


        {currentScreen === "AddPaymentSource" && (
          <AddPaymentSourceScreen
            onBack={() => setCurrentScreen("Deposit")}
            onSave={() => setCurrentScreen("Deposit")}
          />
        )}

        {/* ---------- WITHDRAW ---------- */}
        {currentScreen === "Withdraw" && (
          <WithdrawScreen
            onBack={goHome}
            onConfirm={(data) => {
              setPrevScreen("Withdraw");
              setPendingPayment({ ...data, type: "withdraw" });
              setPendingAction(() => () => setCurrentScreen("PaymentProcessing"));
              setCurrentScreen("ConfirmPayment");
            }}
          />
        )}

        {/* ---------- SAVINGS ---------- */}
        {currentScreen === "SavingsDeposit" && (
          <SavingsDepositScreen
            onBack={goHome}
            onConfirm={(data) => {
              setPrevScreen("SavingsDeposit");
              setPendingPayment({ ...data, type: "savings-deposit" });
              setPendingAction(() => () => setCurrentScreen("PaymentProcessing"));
              setCurrentScreen("ConfirmPayment");
            }}
          />
        )}

        {currentScreen === "SavingsWithdraw" && (
          <SavingsWithdrawScreen
            onBack={goHome}
            onConfirm={(data) => {
              setPrevScreen("SavingsWithdraw");
              setPendingPayment({ ...data, type: "savings-withdraw" });
              setPendingAction(() => () => setCurrentScreen("PaymentProcessing"));
              setCurrentScreen("ConfirmPayment");
            }}
          />
        )}

        {/* ---------- GOAL FUNDING ---------- */}
        {currentScreen === "AddGoalFundScreen" && selectedGoal && (
          <AddGoalFundScreen
            goal={selectedGoal}
            onBack={() => setCurrentScreen("GoalDetailsScreen")}
            onConfirm={(amount) => {
              setPrevScreen("AddGoalFundScreen");
              setPendingPayment({ type: "goal-fund", amount, goalName: selectedGoal.name });
              setPendingAction(() => () => setCurrentScreen("PaymentProcessing"));
              setCurrentScreen("ConfirmPayment");
            }}
          />
        )}

        {currentScreen === "WithdrawGoalScreen" && selectedGoal && (
          <WithdrawGoalScreen
            goal={selectedGoal}
            onBack={() => setCurrentScreen("GoalDetailsScreen")}
            onConfirm={(amount) => {
              setPrevScreen("WithdrawGoalScreen");
              setPendingPayment({ type: "goal-withdraw", amount, goalName: selectedGoal.name });
              setPendingAction(() => () => setCurrentScreen("PaymentProcessing"));
              setCurrentScreen("ConfirmPayment");
            }}
          />
        )}

      </div>
    </CurrencyProvider>
  );
}
